import boto3
import logging
import os
import json
from datetime import datetime

# Initialize logging
logger = logging.getLogger()
logger.setLevel(os.environ.get('LOG_LEVEL', 'INFO').upper())

# Initialize AWS clients
s3_client = boto3.client('s3')
sns_client = boto3.client('sns')

# Configuration from environment variables
SNS_TOPIC_ARN = os.environ.get('SNS_TOPIC_ARN')
OUTPUT_BUCKET_NAME = os.environ.get('OUTPUT_BUCKET_NAME')
# Default region from env var or boto3 config
AWS_REGION = os.environ.get('AWS_REGION', os.environ.get('AWS_DEFAULT_REGION', 'us-east-1'))


def lambda_handler(event, context):
    """
    AWS Lambda function to process user-uploaded images from S3.
    It reads the image, performs a dummy processing, writes a result
    back to S3, and sends an SNS notification.
    """
    logger.info(f"Received event: {json.dumps(event)}")

    # Ensure required environment variables are set
    if not SNS_TOPIC_ARN:
        logger.error("SNS_TOPIC_ARN environment variable is not set.")
        return {
            'statusCode': 500,
            'body': json.dumps('Configuration error: SNS_TOPIC_ARN is missing.')
        }
    if not OUTPUT_BUCKET_NAME:
        logger.error("OUTPUT_BUCKET_NAME environment variable is not set.")
        return {
            'statusCode': 500,
            'body': json.dumps('Configuration error: OUTPUT_BUCKET_NAME is missing.')
        }

    try:
        # Expecting an S3 event from an image upload
        if 'Records' not in event or not event['Records']:
            logger.warning("No S3 records found in the event.")
            return {
                'statusCode': 200,
                'body': json.dumps('No S3 records to process.')
            }

        for record in event['Records']:
            if 's3' not in record:
                logger.warning(f"Record does not contain S3 information: {json.dumps(record)}")
                continue

            bucket_name = record['s3']['bucket']['name']
            object_key = record['s3']['object']['key']

            logger.info(f"Processing file {object_key} from bucket {bucket_name}")

            # 1. Read from S3
            try:
                s3_object = s3_client.get_object(Bucket=bucket_name, Key=object_key)
                image_content = s3_object['Body'].read()
                image_size = len(image_content)
                logger.info(f"Successfully read object {object_key}. Size: {image_size} bytes.")
            except Exception as e:
                logger.error(f"Error reading object {object_key} from bucket {bucket_name}: {e}")
                # Continue to next record or re-raise, depending on error handling strategy
                continue

            # Dummy Processing (replace with actual image processing logic)
            # For demonstration, we'll just create some metadata.
            processed_data = {
                'original_key': object_key,
                'original_bucket': bucket_name,
                'processing_timestamp': datetime.utcnow().isoformat() + 'Z',
                'image_size_bytes': image_size,
                'processing_status': 'COMPLETED',
                'processor_version': '1.0'
            }
            logger.info(f"Dummy processing completed for {object_key}.")

            # 2. Write results back to S3
            output_key = f"processed/{os.path.basename(object_key)}.json"
            try:
                s3_client.put_object(
                    Bucket=OUTPUT_BUCKET_NAME,
                    Key=output_key,
                    Body=json.dumps(processed_data, indent=2),
                    ContentType='application/json'
                )
                logger.info(f"Successfully wrote processed data to s3://{OUTPUT_BUCKET_NAME}/{output_key}")
            except Exception as e:
                logger.error(f"Error writing processed data to s3://{OUTPUT_BUCKET_NAME}/{output_key}: {e}")
                # Continue to next record or re-raise
                continue

            # 3. Send notification via SNS
            try:
                sns_message = {
                    'default': json.dumps({
                        'key': object_key,
                        'bucket': bucket_name,
                        'output_bucket': OUTPUT_BUCKET_NAME,
                        'output_key': output_key,
                        'status': 'Processed',
                        'timestamp': datetime.utcnow().isoformat() + 'Z'
                    }),
                    'email': f"Image '{object_key}' processed successfully. Output: s3://{OUTPUT_BUCKET_NAME}/{output_key}"
                }

                sns_client.publish(
                    TopicArn=SNS_TOPIC_ARN,
                    Message=json.dumps(sns_message),
                    MessageStructure='json',
                    Subject=f"Image Processing Alert: {object_key}"
                )
                logger.info(f"Successfully sent SNS notification for {object_key} to topic {SNS_TOPIC_ARN}")
            except Exception as e:
                logger.error(f"Error sending SNS notification for {object_key}: {e}")
                # Continue to next record or re-raise
                continue

        return {
            'statusCode': 200,
            'body': json.dumps('Image processing initiated for all records.')
        }

    except Exception as e:
        logger.critical(f"Unhandled error during Lambda execution: {e}", exc_info=True)
        return {
            'statusCode': 500,
            'body': json.dumps(f'Internal server error: {e}')
        }